/**
 * ESLint rule: no-cross-module-imports
 *
 * Запрещает компонентам импортировать компоненты не из своего поддерева согласно п.11 документации:
 * "Компоненты не должны импортировать компоненты не из своего поддерева компонентов 
 * (если это требуется, то компонент необходимо сделать общим)"
 *
 * Разрешенные импорты компонентов:
 * - Из @app/shared/components (общие компоненты)
 * - Из своего поддерева (./components/, ../components/ в рамках одного модуля)
 * - Библиотечные компоненты (@bodynarf/react.components, etc.)
 *
 * Запрещенные импорты:
 * - Из других модулей (../../../другой-модуль/components/)
 */

export default {
  meta: {
    type: "problem",
    docs: {
      description: "Prevent components from importing components outside their subtree",
      category: "Best Practices",
      recommended: true
    },
    fixable: null,
    schema: [],
    messages: {
      crossModuleImport: "Component '{{component}}' should not import '{{importPath}}' from another module. Consider moving it to @app/shared/components if it needs to be reused.",
      useSharedComponent: "Instead of importing from '{{importPath}}', use or create a shared component in @app/shared/components"
    },
  },

  create(context) {
    /**
     * Проверяет, является ли путь импортом компонента
     * @param {string} importPath - путь импорта
     * @returns {boolean}
     */
    function isComponentImport(importPath) {
      // Импорты компонентов - это относительные пути, содержащие 'component' или заканчивающиеся на компонент
      return (
        importPath.startsWith('./') || 
        importPath.startsWith('../')
      ) && (
        importPath.includes('/component') ||
        importPath.includes('/components/') ||
        // Импорт файла без расширения (вероятно компонент)
        !/\.(scss|css|json|ts|js)$/.test(importPath)
      );
    }

    /**
     * Проверяет, является ли импорт разрешенным
     * @param {string} importPath - путь импорта
     * @param {string} currentFilePath - путь текущего файла
     * @returns {boolean}
     */
    function isAllowedImport(importPath, currentFilePath) {
      // Разрешены импорты из shared/components
      if (importPath.startsWith('@app/shared/components')) {
        return true;
      }

      // Разрешены библиотечные компоненты (не относительные пути)
      if (!importPath.startsWith('./') && !importPath.startsWith('../')) {
        return true;
      }

      // Разрешены импорты в рамках своего модуля
      return isWithinSameModule(importPath, currentFilePath);
    }

    /**
     * Проверяет, находится ли импорт в рамках того же модуля
     * @param {string} importPath - путь импорта
     * @param {string} currentFilePath - путь текущего файла
     * @returns {boolean}
     */
    function isWithinSameModule(importPath, currentFilePath) {
      // Нормализуем пути для анализа
      const currentDir = currentFilePath.replace(/\\/g, '/');
      
      // Найти корень модуля (папка, содержащая component/index.tsx или index.ts)
      const moduleRoot = findModuleRoot(currentDir);
      if (!moduleRoot) return true; // Если не можем определить модуль, разрешаем

      // Подсчитываем количество "../" в начале importPath
      const upLevels = (importPath.match(/\.\.\//g) || []).length;
      
      // Если слишком много уровней вверх, это может быть другой модуль
      if (upLevels > 3) {
        return false;
      }

      // Проверяем, не выходим ли мы за пределы модуля
      const currentDepth = (currentDir.split('/').length - moduleRoot.split('/').length);
      
      // Если идем вверх больше чем на глубину от корня модуля, это другой модуль
      return upLevels <= currentDepth + 1;
    }

    /**
     * Находит корень модуля для файла
     * @param {string} filePath - путь к файлу
     * @returns {string|null} путь к корню модуля
     */
    function findModuleRoot(filePath) {
      const pathParts = filePath.split('/');
      
      // Ищем папку modules в пути
      const modulesIndex = pathParts.findIndex(part => part === 'modules');
      if (modulesIndex === -1) return null;
      
      // Корень модуля - следующая папка после modules
      if (modulesIndex + 1 < pathParts.length) {
        return pathParts.slice(0, modulesIndex + 2).join('/');
      }
      
      return null;
    }

    /**
     * Получает имя компонента из пути файла
     * @param {string} filePath - путь к файлу
     * @returns {string} имя компонента
     */
    function getComponentName(filePath) {
      const pathParts = filePath.split(/[/\\]/);
      // Ищем папку компонента (обычно перед index.tsx или содержащая component)
      for (let i = pathParts.length - 1; i >= 0; i--) {
        if (pathParts[i] === 'components' && i + 1 < pathParts.length) {
          return pathParts[i + 1];
        }
        if (pathParts[i] === 'component' && i > 0) {
          return pathParts[i - 1];
        }
      }
      return pathParts[pathParts.length - 2] || 'Unknown';
    }

    return {
      ImportDeclaration(node) {
        const importPath = node.source.value;
        const currentFilePath = context.getFilename();
        
        // Проверяем только импорты компонентов
        if (!isComponentImport(importPath)) {
          return;
        }

        // Проверяем, разрешен ли импорт
        if (!isAllowedImport(importPath, currentFilePath)) {
          const componentName = getComponentName(currentFilePath);
          
          context.report({
            node: node,
            messageId: "crossModuleImport",
            data: {
              component: componentName,
              importPath: importPath
            }
          });
        }
      }
    };
  }
};
